features.snippet:
reg [1:0] state;
wire _GEN = state == 2'h0;
wire _GEN_0 = state == 2'h1;
wire _GEN_1 = _GEN_0 & ~(step[2]);
always @(posedge clock) begin
  if (reset) state <= 2'h0;
  else if (_GEN) begin
    if (io_start) state <= 2'h1;
  end
  else begin
    if (_GEN_0 & step[2]) state <= 2'h2;
  end
end

always @(posedge clock) begin
  if (reset) begin
    state <= 2'h0;
    step <= 3'h0;
  end
  else if (_GEN) begin
    if (io_start) state <= 2'h1;
  end
  else begin
    if (_GEN_0 & step[2]) state <= 2'h2;
    if (_GEN_1) step <= step + 3'h1;
  end
end

